#!/usr/bin/env bash
# Adds the shmora favicon (brand sharpener glyph on orange background)
# to the frontend. Run this from the repository root (the folder that
# contains "frontend/").
set -e

if [ ! -d "frontend/public" ]; then
  echo "ERROR: run this script from the repo root (frontend/public not found)"
  exit 1
fi

cd frontend/public

# 1. favicon.svg (scalable, modern browsers)
cat > favicon.svg << 'SVGEOF'
